using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    public string Category { get; set; } = string.Empty;

    [Required, MinLength(1)]
    public List<string> Ingredients { get; set; } = new();

    [Required, MinLength(1)]
    public List<string> Steps { get; set; } = new();

    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly List<RecipeCategory> _categories;

    public RecipeService()
    {
        _categories = new List<RecipeCategory>
        {
            new() { Name = "Breakfast", Description = "Start your day right", Icon = "🥞" },
            new() { Name = "Lunch", Description = "Midday meals and sandwiches", Icon = "🥗" },
            new() { Name = "Dinner", Description = "Hearty evening recipes", Icon = "🍝" },
            new() { Name = "Desserts", Description = "Sweet treats and baked goods", Icon = "🍰" },
            new() { Name = "Snacks", Description = "Quick bites and appetizers", Icon = "🧀" },
            new() { Name = "Drinks", Description = "Smoothies, cocktails, and more", Icon = "🥤" }
        };

        _recipes = new List<Recipe>
        {
            new()
            {
                Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
                Ingredients = new() { "2 cups flour", "2 eggs", "1.5 cups milk", "2 tbsp sugar", "1 tsp baking powder", "Pinch of salt" },
                Steps = new() { "Mix dry ingredients together.", "Whisk eggs and milk, then combine with dry mix.", "Heat a buttered pan over medium heat.", "Pour batter and cook until bubbles form, then flip.", "Serve with maple syrup and fresh berries." },
                AverageRating = 4.5, RatingCount = 12
            },
            new()
            {
                Id = 2, Title = "Caesar Salad", Category = "Lunch",
                Ingredients = new() { "1 head romaine lettuce", "1/2 cup croutons", "1/4 cup parmesan", "Caesar dressing", "Grilled chicken (optional)" },
                Steps = new() { "Wash and chop the romaine lettuce.", "Toss with Caesar dressing.", "Top with croutons and shaved parmesan.", "Add grilled chicken if desired." },
                AverageRating = 4.2, RatingCount = 8
            },
            new()
            {
                Id = 3, Title = "Spaghetti Bolognese", Category = "Dinner",
                Ingredients = new() { "400g spaghetti", "500g ground beef", "1 can crushed tomatoes", "1 onion, diced", "3 cloves garlic", "Fresh basil", "Olive oil" },
                Steps = new() { "Cook spaghetti according to package directions.", "Sauté onion and garlic in olive oil.", "Add ground beef and brown.", "Pour in crushed tomatoes and simmer 20 minutes.", "Season with salt, pepper, and fresh basil.", "Serve sauce over spaghetti." },
                AverageRating = 4.8, RatingCount = 25
            },
            new()
            {
                Id = 4, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Ingredients = new() { "2.25 cups flour", "1 cup butter, softened", "3/4 cup sugar", "3/4 cup brown sugar", "2 eggs", "1 tsp vanilla", "1 tsp baking soda", "2 cups chocolate chips" },
                Steps = new() { "Preheat oven to 375°F (190°C).", "Cream butter and sugars until fluffy.", "Beat in eggs and vanilla.", "Mix in flour and baking soda.", "Fold in chocolate chips.", "Drop spoonfuls onto baking sheet.", "Bake 9-11 minutes until golden." },
                AverageRating = 4.9, RatingCount = 42
            },
            new()
            {
                Id = 5, Title = "Guacamole", Category = "Snacks",
                Ingredients = new() { "3 ripe avocados", "1 lime, juiced", "1/2 tsp salt", "1/2 cup diced onion", "3 tbsp fresh cilantro", "2 roma tomatoes, diced", "1 tsp minced garlic" },
                Steps = new() { "Halve avocados and remove pit.", "Mash avocado in a bowl.", "Stir in lime juice and salt.", "Mix in onion, cilantro, tomatoes, and garlic.", "Serve immediately with tortilla chips." },
                AverageRating = 4.6, RatingCount = 15
            },
            new()
            {
                Id = 6, Title = "Mango Smoothie", Category = "Drinks",
                Ingredients = new() { "1 cup frozen mango", "1 banana", "1 cup yogurt", "1/2 cup orange juice", "1 tbsp honey" },
                Steps = new() { "Add all ingredients to a blender.", "Blend until smooth.", "Pour into a glass and serve immediately." },
                AverageRating = 4.3, RatingCount = 9
            }
        };
    }

    public List<RecipeCategory> GetCategories() => _categories;

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public List<Recipe> GetAllRecipes() => _recipes;

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            var totalStars = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = (totalStars + stars) / recipe.RatingCount;
        }
    }
}

