arguments.file_text:
@page "/recipes/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<div class="container">
    <nav class="breadcrumb">
        <a href="/">Home</a> &rsaquo; <span>@CategoryName</span>
    </nav>

    <h1>@CategoryName Recipes</h1>

    @if (recipes.Count == 0)
    {
        <p>No recipes found in this category yet. <a href="/submit">Be the first to submit one!</a></p>
    }
    else
    {
        <div class="recipe-list">
            @foreach (var recipe in recipes)
            {
                <a href="/recipe/@recipe.Id" class="recipe-card">
                    <h3>@recipe.Title</h3>
                    <div class="recipe-meta">
                        <span class="stars">@GetStars(recipe.AverageRating)</span>
                        <span class="rating-count">(@recipe.RatingCount ratings)</span>
                    </div>
                </a>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<RecipeShare.Models.Recipe> recipes = new();

    protected override void OnParametersSet()
    {
        var categoryDisplay = System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(CategoryName);
        CategoryName = categoryDisplay;
        recipes = RecipeService.GetRecipesByCategory(categoryDisplay);
    }

    private string GetStars(double rating)
    {
        var full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

<div class="container">
    @if (recipe is null)
    {
        <p>Recipe not found.</p>
    }
    else
    {
        <nav class="breadcrumb">
            <a href="/">Home</a> &rsaquo; <a href="/recipes/@recipe.Category.ToLower()">@recipe.Category</a> &rsaquo; <span>@recipe.Title</span>
        </nav>

        <article class="recipe-detail">
            <h1>@recipe.Title</h1>

            <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />

            <section class="ingredients">
                <h2>🧾 Ingredients</h2>
                <ul>
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li>@ingredient</li>
                    }
                </ul>
            </section>

            <section class="steps">
                <h2>📝 Steps</h2>
                <ol>
                    @foreach (var step in recipe.Steps)
                    {
                        <li>@step</li>
                    }
                </ol>
            </section>
        </article>
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="star-rating">
    <div class="stars-interactive">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button @onclick="() => Rate(star)"
                    @onmouseover="() => hoverStar = star"
                    @onmouseout="() => hoverStar = 0"
                    class="star-btn @(IsHighlighted(star) ? "highlighted" : "")"
                    aria-label="Rate @star stars">
                @(IsHighlighted(star) ? "★" : "☆")
            </button>
        }
    </div>
    <span class="rating-display">
        @if (submitted)
        {
            <span class="rating-thanks">Thanks for rating!</span>
        }
        @CurrentRating.ToString("0.0") / 5 (@RatingCount ratings)
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int hoverStar;
    private bool submitted;

    private bool IsHighlighted(int star) => star <= (hoverStar > 0 ? hoverStar : (int)Math.Round(CurrentRating));

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<div class="container">
    <h1>📝 Submit a Recipe</h1>

    @if (successMessage is not null)
    {
        <div class="alert-success">
            <p>@successMessage</p>
            <a href="/recipe/@submittedId">View your recipe</a>
        </div>
    }
    else
    {
        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
            <DataAnnotationsValidator />
            <ValidationSummary />

            <div class="form-group">
                <label for="title">Recipe Title</label>
                <InputText id="title" @bind-Value="model.Title" placeholder="e.g. Grandma's Apple Pie" />
                <ValidationMessage For="() => model.Title" />
            </div>

            <div class="form-group">
                <label for="category">Category</label>
                <InputSelect id="category" @bind-Value="model.Category">
                    <option value="">— Select a category —</option>
                    @foreach (var cat in RecipeService.GetCategories())
                    {
                        <option value="@cat.Name">@cat.Icon @cat.Name</option>
                    }
                </InputSelect>
            </div>

            <div class="form-group">
                <label>Ingredients (one per line)</label>
                <InputTextArea @bind-Value="ingredientsText" rows="6" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            </div>

            <div class="form-group">
                <label>Steps (one per line)</label>
                <InputTextArea @bind-Value="stepsText" rows="6" placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;..." />
            </div>

            <button type="submit" class="btn-primary">Submit Recipe</button>
        </EditForm>
    }
</div>

@code {
    private Recipe model = new();
    private string ingredientsText = string.Empty;
    private string stepsText = string.Empty;
    private string? successMessage;
    private int submittedId;

    private void HandleSubmit()
    {
        model.Ingredients = ingredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        model.Steps = stepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

