.category-card:hover { transform: translateY(-3px); box-shadow: 0 4px 16px rgba(0,0,0,0.12); }
.category-icon { font-size: 2.5rem; }
.category-card h3 { margin: 0.5rem 0 0.25rem; }
.category-card p { color: var(--text-muted); font-size: 0.9rem; }

/* CTA */
.cta-section { text-align: center; padding: 3rem 0; margin-top: 2rem; }
.cta-section h2 { margin-bottom: 0.5rem; }
.btn-primary { display: inline-block; background: var(--primary); color: white; padding: 0.75rem 1.5rem; border-radius: var(--radius); text-decoration: none; font-weight: 600; border: none; font-size: 1rem; cursor: pointer; margin-top: 1rem; }
.btn-primary:hover { background: var(--primary-dark); }

/* Breadcrumb */
.breadcrumb { margin-bottom: 1.5rem; color: var(--text-muted); }
.breadcrumb a { color: var(--primary); text-decoration: none; }

/* Recipe List */
.recipe-list { display: grid; gap: 1rem; }
.recipe-card { display: block; background: var(--surface); border-radius: var(--radius); padding: 1.25rem; text-decoration: none; color: var(--text); box-shadow: var(--shadow); transition: transform 0.2s; }
.recipe-card:hover { transform: translateY(-2px); }
.recipe-card h3 { margin-bottom: 0.25rem; }
.recipe-meta { color: var(--text-muted); font-size: 0.9rem; }
.stars { color: #f59e0b; letter-spacing: 2px; }

/* Recipe Detail */
.recipe-detail h1 { margin-bottom: 0.5rem; }
.recipe-detail section { margin: 2rem 0; }
.recipe-detail h2 { margin-bottom: 0.75rem; }
.recipe-detail ul, .recipe-detail ol { padding-left: 1.5rem; }
.recipe-detail li { margin-bottom: 0.4rem; }

/* Star Rating Widget */
.star-rating { display: flex; align-items: center; gap: 1rem; margin: 1rem 0; flex-wrap: wrap; }
.stars-interactive { display: flex; gap: 0.1rem; }
.star-btn { background: none; border: none; font-size: 1.8rem; cursor: pointer; color: #d1d5db; padding: 0; line-height: 1; transition: transform 0.1s; }
.star-btn.highlighted { color: #f59e0b; }
.star-btn:hover { transform: scale(1.2); }
.rating-display { font-size: 0.9rem; color: var(--text-muted); }
.rating-thanks { color: #16a34a; font-weight: 600; margin-right: 0.5rem; }

/* Form Styles */
.form-group { margin-bottom: 1.5rem; }
.form-group label { display: block; font-weight: 600; margin-bottom: 0.4rem; }
.form-group input, .form-group select, .form-group textarea { width: 100%; padding: 0.6rem 0.8rem; border: 1px solid #d1d5db; border-radius: var(--radius); font-size: 1rem; font-family: inherit; }
.form-group textarea { resize: vertical; }
.form-group input:focus, .form-group select:focus, .form-group textarea:focus { outline: none; border-color: var(--primary); box-shadow: 0 0 0 3px rgba(232, 93, 4, 0.15); }

.alert-success { background: #d1fae5; border: 1px solid #6ee7b7; border-radius: var(--radius); padding: 1rem 1.5rem; margin-bottom: 1.5rem; }
.alert-success a { color: var(--primary); font-weight: 600; }

.validation-message { color: #dc2626; font-size: 0.85rem; margin-top: 0.25rem; }

#blazor-error-ui { background: #dc2626; color: white; padding: 0.5rem; text-align: center; display: none; }
#blazor-error-ui[style] { display: block; }
EOF

